class Solution:
    def addDigits(self, num):
        while num >= 10:
            s = 0
            while num:
                s += num % 10
                num //= 10
            num = s
        return num

solutions.python:
class Solution:
    def addDigits(self, num):
        if num == 0:
            return 0
        return 1 + (num - 1) % 9

